        "question_id": "1krxjjxgo",
        "chapterId": "area-under-the-curves",
        "title": "JEE Main 2021 (Online) 27th July Evening Shift",
        "year": 2021,
        "difficulty": "Medium",
        "type": "SCQ",
        "question": "The area of the region bounded by y $$-$$ x = 2 and x<sup>2</sup> = y is equal to :",
